    lam = 1.0 - beta
    rho0 = np.array([[0.5, 0.5], [0.5, 0.5]], dtype=complex)      # puro |+>
    rho_star = np.array([[0.5, 0.0], [0.0, 0.5]], dtype=complex)  # atrator
    def _phi(r):
        out = r.copy(); out[0, 1] *= lam; out[1, 0] *= lam
        return out
